import React from 'react';
import { ProductFilter } from './ProductFilter';
import './styles.css';

const products = [
  { id: 'p1', name: 'Wireless Mouse', category: 'electronics', price: 29.99 },
  { id: 'p2', name: 'Mechanical Keyboard', category: 'electronics', price: 149.99 },
  { id: 'p3', name: 'Running Shoes', category: 'sports', price: 89.99 },
  { id: 'p4', name: 'Yoga Mat', category: 'sports', price: 24.99 },
  { id: 'p5', name: 'Coffee Maker', category: 'home', price: 59.99 },
  { id: 'p6', name: 'Standing Desk', category: 'home', price: 399.99 },
  { id: 'p7', name: 'Bluetooth Speaker', category: 'electronics', price: 45.99 },
  { id: 'p8', name: 'Water Bottle', category: 'sports', price: 15.99 },
];

export default function App() {
  return (
    <div style={{ padding: '2rem', fontFamily: 'system-ui, sans-serif' }}>
      <h1 style={{ marginBottom: '1.5rem' }}>Product Filter</h1>
      <ProductFilter products={products} />
    </div>
  );
}

import React, { useReducer, useMemo } from 'react';
import './styles.css';

// --- Types ---
export interface Product {
  id: string;
  name: string;
  category: string;
  price: number;
}

export interface FilterState {
  search: string;
  category: string;
  priceRange: [number, number];
}

type FilterAction =
  | { type: 'SET_SEARCH'; search: string }
  | { type: 'SET_CATEGORY'; category: string }
  | { type: 'SET_PRICE_RANGE'; min: number; max: number }
  | { type: 'RESET_FILTERS' };

const initialState: FilterState = {
  search: '',
  category: 'all',
  priceRange: [0, 1000],
};

// --- Reducer ---
export function filterReducer(state: FilterState, action: FilterAction): FilterState {
  switch (action.type) {
    case 'SET_SEARCH':
      // TODO: Update search field
      return state;
    case 'SET_CATEGORY':
      // TODO: Update category field
      return state;
    case 'SET_PRICE_RANGE':
      // TODO: Update priceRange field
      return state;
    case 'RESET_FILTERS':
      // TODO: Reset to initialState
      return state;
    default:
      return state;
  }
}

// --- Component ---
interface ProductFilterProps {
  products: Product[];
}

export const ProductFilter: React.FC<ProductFilterProps> = ({ products }) => {
  const [state, dispatch] = useReducer(filterReducer, initialState);

  // TODO: Derive filteredProducts using useMemo
  // Apply all filters: search (case-insensitive), category, priceRange
  const filteredProducts = products;

  const categories = ['all', ...Array.from(new Set(products.map(p => p.category)))];

  return (
    <div className="filter-layout">
      <div className="filter-controls">
        <input
          data-testid="search-input"
          className="filter-input"
          value={state.search}
          onChange={e => dispatch({ type: 'SET_SEARCH', search: e.target.value })}
          placeholder="Search products…"
        />
        <select
          data-testid="category-select"
          className="filter-select"
          value={state.category}
          onChange={e => dispatch({ type: 'SET_CATEGORY', category: e.target.value })}
        >
          {categories.map(c => (
            <option key={c} value={c}>{c === 'all' ? 'All Categories' : c}</option>
          ))}
        </select>
        <div className="filter-price-range">
          <input
            data-testid="min-price"
            type="number"
            className="filter-input filter-input--small"
            value={state.priceRange[0]}
            onChange={e => dispatch({ type: 'SET_PRICE_RANGE', min: Number(e.target.value), max: state.priceRange[1] })}
            placeholder="Min"
          />
          <span>—</span>
          <input
            data-testid="max-price"
            type="number"
            className="filter-input filter-input--small"
            value={state.priceRange[1]}
            onChange={e => dispatch({ type: 'SET_PRICE_RANGE', min: state.priceRange[0], max: Number(e.target.value) })}
            placeholder="Max"
          />
        </div>
        <button data-testid="reset-filters" className="filter-reset" onClick={() => dispatch({ type: 'RESET_FILTERS' })}>
          Reset
        </button>
      </div>
      <p className="filter-count" data-testid="result-count">{filteredProducts.length} products found</p>
      <div className="filter-results">
        {filteredProducts.map(p => (
          <div key={p.id} data-testid={`product-${p.id}`} className="filter-card">
            <h3>{p.name}</h3>
            <p className="filter-card__meta">{p.category} · ${p.price.toFixed(2)}</p>
          </div>
        ))}
      </div>
    </div>
  );
};

.filter-layout {
  max-width: 40rem;
}

.filter-controls {
  display: flex;
  flex-wrap: wrap;
  gap: 0.75rem;
  margin-bottom: 1rem;
}

.filter-input {
  padding: 0.5rem 0.75rem;
  border: 1px solid #d1d5db;
  border-radius: 0.375rem;
  font-size: 0.875rem;
  outline: none;
}

.filter-input:focus {
  border-color: #3b82f6;
}

.filter-input--small {
  width: 5rem;
}

.filter-select {
  padding: 0.5rem 0.75rem;
  border: 1px solid #d1d5db;
  border-radius: 0.375rem;
  font-size: 0.875rem;
  background: white;
}

.filter-price-range {
  display: flex;
  align-items: center;
  gap: 0.5rem;
}

.filter-reset {
  padding: 0.5rem 1rem;
  border: 1px solid #d1d5db;
  border-radius: 0.375rem;
  background: #f9fafb;
  cursor: pointer;
  font-size: 0.875rem;
}

.filter-count {
  font-size: 0.8125rem;
  color: #6b7280;
  margin-bottom: 1rem;
}

.filter-results {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(14rem, 1fr));
  gap: 1rem;
}

.filter-card {
  padding: 1rem;
  border: 1px solid #e5e7eb;
  border-radius: 0.5rem;
  background: white;
}

.filter-card h3 {
  margin: 0 0 0.25rem;
  font-size: 0.9375rem;
}

.filter-card__meta {
  margin: 0;
  font-size: 0.8125rem;
  color: #6b7280;
