import { render, screen, fireEvent } from '@testing-library/react';
import '@testing-library/jest-dom';
import React from 'react';
import { filterReducer } from './ProductFilter';

const initial = { search: '', category: 'all', priceRange: [0, 1000] as [number, number] };

describe('filterReducer', () => {
  it('updates search', () => {
    const result = filterReducer(initial, { type: 'SET_SEARCH', search: 'mouse' });
    expect(result.search).toBe('mouse');
  });

  it('updates category', () => {
    const result = filterReducer(initial, { type: 'SET_CATEGORY', category: 'electronics' });
    expect(result.category).toBe('electronics');
  });

  it('updates price range', () => {
    const result = filterReducer(initial, { type: 'SET_PRICE_RANGE', min: 10, max: 100 });
    expect(result.priceRange).toEqual([10, 100]);
  });

  it('resets to initial state', () => {
    const modified = { search: 'test', category: 'sports', priceRange: [50, 200] as [number, number] };
    const result = filterReducer(modified, { type: 'RESET_FILTERS' });
    expect(result).toEqual(initial);
  });

  it('preserves other fields when updating search', () => {
    const state = { ...initial, category: 'home' };
    const result = filterReducer(state, { type: 'SET_SEARCH', search: 'desk' });
    expect(result.category).toBe('home');
    expect(result.search).toBe('desk');
  });
});

describe('ProductFilter integration', () => {
  const products = [
    { id: 'p1', name: 'Wireless Mouse', category: 'electronics', price: 29.99 },
    { id: 'p2', name: 'Keyboard', category: 'electronics', price: 149.99 },
    { id: 'p3', name: 'Running Shoes', category: 'sports', price: 89.99 },
    { id: 'p4', name: 'Yoga Mat', category: 'sports', price: 24.99 },
  ];

  function renderFilter() {
    const { ProductFilter } = require('./ProductFilter');
    render(<ProductFilter products={products} />);
  }

  it('shows all products initially', () => {
    renderFilter();
    expect(screen.getByTestId('result-count')).toHaveTextContent('4');
  });

  it('filters by search text', () => {
    renderFilter();
    fireEvent.change(screen.getByTestId('search-input'), { target: { value: 'mouse' } });
    expect(screen.getByTestId('result-count')).toHaveTextContent('1');
  });

  it('filters by category', () => {
    renderFilter();
    fireEvent.change(screen.getByTestId('category-select'), { target: { value: 'sports' } });
    expect(screen.getByTestId('result-count')).toHaveTextContent('2');
  });

  it('resets all filters', () => {
    renderFilter();
    fireEvent.change(screen.getByTestId('search-input'), { target: { value: 'xyz' } });
    fireEvent.click(screen.getByTestId('reset-filters'));
    expect(screen.getByTestId('result-count')).toHaveTextContent('4');
  });
});

