import React, { useReducer, useMemo } from 'react';
import './styles.css';

export interface Product {
  id: string;
  name: string;
  category: string;
  price: number;
}

export interface FilterState {
  search: string;
  category: string;
  priceRange: [number, number];
}

type FilterAction =
  | { type: 'SET_SEARCH'; search: string }
  | { type: 'SET_CATEGORY'; category: string }
  | { type: 'SET_PRICE_RANGE'; min: number; max: number }
  | { type: 'RESET_FILTERS' };

const initialState: FilterState = {
  search: '',
  category: 'all',
  priceRange: [0, 1000],
};

export function filterReducer(state: FilterState, action: FilterAction): FilterState {
  switch (action.type) {
    case 'SET_SEARCH':
      return { ...state, search: action.search };
    case 'SET_CATEGORY':
      return { ...state, category: action.category };
    case 'SET_PRICE_RANGE':
      return { ...state, priceRange: [action.min, action.max] };
    case 'RESET_FILTERS':
      return initialState;
    default:
      return state;
  }
}

interface ProductFilterProps {
  products: Product[];
}

export const ProductFilter: React.FC<ProductFilterProps> = ({ products }) => {
  const [state, dispatch] = useReducer(filterReducer, initialState);

  const filteredProducts = useMemo(() => {
    return products.filter(p => {
      const matchesSearch = p.name.toLowerCase().includes(state.search.toLowerCase());
      const matchesCategory = state.category === 'all' || p.category === state.category;
      const matchesPrice = p.price >= state.priceRange[0] && p.price <= state.priceRange[1];
      return matchesSearch && matchesCategory && matchesPrice;
    });
  }, [products, state]);

  const categories = ['all', ...Array.from(new Set(products.map(p => p.category)))];

  return (
    <div className="filter-layout">
      <div className="filter-controls">
        <input
          data-testid="search-input"
          className="filter-input"
          value={state.search}
          onChange={e => dispatch({ type: 'SET_SEARCH', search: e.target.value })}
          placeholder="Search products…"
        />
        <select
          data-testid="category-select"
          className="filter-select"
          value={state.category}
          onChange={e => dispatch({ type: 'SET_CATEGORY', category: e.target.value })}
        >
          {categories.map(c => (
            <option key={c} value={c}>{c === 'all' ? 'All Categories' : c}</option>
          ))}
        </select>
        <div className="filter-price-range">
          <input
            data-testid="min-price"
            type="number"
            className="filter-input filter-input--small"
            value={state.priceRange[0]}
            onChange={e => dispatch({ type: 'SET_PRICE_RANGE', min: Number(e.target.value), max: state.priceRange[1] })}
            placeholder="Min"
          />
          <span>—</span>
          <input
            data-testid="max-price"
            type="number"
            className="filter-input filter-input--small"
            value={state.priceRange[1]}
            onChange={e => dispatch({ type: 'SET_PRICE_RANGE', min: state.priceRange[0], max: Number(e.target.value) })}
            placeholder="Max"
          />
        </div>
        <button data-testid="reset-filters" className="filter-reset" onClick={() => dispatch({ type: 'RESET_FILTERS' })}>
          Reset
        </button>
      </div>
      <p className="filter-count" data-testid="result-count">{filteredProducts.length} products found</p>
      <div className="filter-results">
        {filteredProducts.map(p => (
          <div key={p.id} data-testid={`product-${p.id}`} className="filter-card">
            <h3>{p.name}</h3>
            <p className="filter-card__meta">{p.category} · ${p.price.toFixed(2)}</p>
          </div>
        ))}
      </div>
    </div>
  );
};
